from agno import Team
from vex import verify, Guardrail

@verify([
    Guardrail('consistency_check', 'Team outputs must align'),
    Guardrail('section_508', 'Accessible for screen readers'),
    Guardrail('no_hallucinations', 'No fabricated student history')
])
def education_team_pipeline(student_query):
    team = Team([
        'curriculum_agent',
        'assessment_agent',
        'accessibility_agent'
    ])
    return team.run(student_query)

plan = education_team_pipeline('Explain fractions to 4th grader')
